        IRBuilder builder(module);
        return makeUntaggedUnionType(
            cast<IRTypeSet>(builder.getSingletonSet(kIROp_TypeSet, unboundedElement)));
    }

    return makeUntaggedUnionType(cast<IRTypeSet>(elementOfSetType->getSet()));
}

